INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00450', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲乙為夫妻。乙得知甲外遇，大吵大鬧表示欲離婚，乙先覓得友人丙於離婚協議書上簽名。後甲 終於亦同意離婚，向乙索得協議書後，甲覓得友人丁簽名。甲乙間離婚行為之法律效力為何？', '["離婚已因甲乙合意而發生離婚效力", "後甲拒不登記，乙得訴請甲協同為離婚登記", "縱持該協議書完成離婚登記，但欠缺離婚實質意思，離婚無效", "未有足夠證人親見親聞雙方離婚真意，實務上認為該離婚無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00451', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲夫乙妻育有未成年丙。下列敘述，何者正確？', '["甲乙既為丙之父母，不論何時，甲乙均為丙之法定代理人", "丙離去甲乙之住所，甲乙得訴請丙履行同居義務", "甲乙不繼續共同生活達6個月以上時，須依協議決定丙之親權行使，否則由法院決定之", "甲乙離婚後，應由甲乙繼續共同行使負擔對丙之權利義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00452', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列何者為有效之遺囑？', '["甲因插管無法言語，遂指示由乙以電腦打字列印後，甲以點頭同意所印內容後，由乙、丙、丁 三人見證宣讀，並全體簽名之遺囑", "甲因中風無法行動，於病床前指示其兒女乙丙見證並口授遺囑，將該遺囑意旨作成書面並記明 年、月、日，並全體簽名於上之遺囑", "甲在依民法規定成立之遺囑中，載明全部財產僅給予兒子乙一人，不給予其餘子女", "甲因車禍倒臥病床，緊急口授遺囑，經手術後，甲已能以其他方式為遺囑時，半年後出院"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00453', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '關於遺產繼承人之順序及應繼分，下列敘述，何者正確？', '["遺產繼承人，除配偶外，其繼承順序為直系血親卑親屬、父母、兄弟姊妹、祖父母", "直系血親卑親屬於繼承開始前死亡者，由其旁系血親卑親屬代位繼承其應繼分", "同一順序之繼承人有數人時，以未成年人優先受分配全部遺產之一半，其餘由其他繼承人平均 分配之", "配偶僅採法定財產制者，始有相互繼承遺產之權利"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00454', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲有乙丙2子。甲因乙出國留學而借予乙新臺幣（下同）100萬元，乙另向丁銀行借得100萬元。 乙學成歸國時沒有結餘，恰逢甲過世，甲則留下200萬元存款。下列敘述，何者錯誤？', '["丙有150萬元應繼分", "丁得就乙之應繼分受償75萬元", "乙應自150萬元應繼分扣還100萬元債務", "乙對於甲之借款返還義務，不因繼承而消滅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00455', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲授與代理權於乙，下列敘述，何者正確？', '["若甲為18歲之限制行為能力人，未經法定代理人同意，該授權行為效力未定", "若乙為18歲之限制行為能力人，未經法定代理人同意，乙仍取得代理人之資格", "代理權之授與，應以書面為之", "代理權之授與，使本人與代理人間發生債權契約關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00456', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於贈與契約之敘述，何者錯誤？', '["為履行道德上義務而為贈與者，贈與物之權利已一部移轉者，不得就其未移轉之部分撤銷之", "贈與人僅就其故意或重大過失，對於受贈人負給付不能之責任", "未經公證之贈與，贈與物之權利未移轉前，贈與人得撤銷其贈與", "經公證之贈與，贈與人因可歸責於自己之事由致給付不能時，受贈人得請求賠償贈與物之價額， 並得請求遲延利息或其他不履行之損害賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00457', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲受乙委託幫忙打掃房舍。甲見乙家有一市價新臺幣（下同）60萬元之鑽石戒指，竊取而占為己 有後，以100萬元高價賣給不知情之收藏家丙，2年後，乙始發現戒指被竊。下列敘述，何者 正確？', '["乙向甲主張侵權行為之損害賠償請求權，得取回100萬元", "乙向甲主張不法管理，得取回100萬元", "乙向甲主張不當得利，得取回100萬元", "乙向甲主張無權代理，得取回100萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00458', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '合夥人執行合夥事務，未受有報酬者，依民法規定，應負何種責任？', '["故意責任", "故意或重大過失責任", "具體輕過失責任", "抽象輕過失責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "032b153805c2", "answer_pdf_sha1": "0041555f981b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00459', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '依司法院大法官之解釋，有關新聞自由之敘述，下列何者正確？', '["唯有報導政治事務之內容，才受新聞自由之憲法保障", "受新聞自由保障之客體，不包括娛樂與運動新聞", "受新聞自由保障之客體，僅限於報導最終呈現之內容", "受新聞自由保障之主體，包括從事新聞工作之個人與事業在內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
